    lv_obj_set_style_pad_column(ui_accessConnectivityCtn, 0, LV_PART_MAIN | LV_STATE_DEFAULT);

    ui_passwordFieldConnectivity = lv_textarea_create(ui_accessConnectivityCtn);
    lv_obj_set_width(ui_passwordFieldConnectivity, lv_pct(100));
    lv_obj_set_height(ui_passwordFieldConnectivity, LV_SIZE_CONTENT);    /// 70
    lv_obj_set_align(ui_passwordFieldConnectivity, LV_ALIGN_CENTER);
    lv_textarea_set_placeholder_text(ui_passwordFieldConnectivity, "Insert the password...");
